import random
import math
from collections import defaultdict

def get_best_schedule(workload, num_seqs):
    n = workload.num_txns
    cost_cache = {}

    def get_cost(schedule):
        key = tuple(schedule)
        if key in cost_cache:
            return cost_cache[key]
        cost = workload.get_opt_seq_cost(schedule)
        cost_cache[key] = cost
        return cost

    profiles = []
    for i in range(n):
        txn = workload.txns[i]
        reads = set()
        writes = set()
        length = 0
        for op in txn:
            op_type, key, pos, txn_len = op
            if op_type == 'r':
                reads.add(key)
            else:
                writes.add(key)
            length = txn_len
        profiles.append({
            'reads': reads,
            'writes': writes,
            'length': length,
            'id': i
        })

    def has_conflict(i, j):
        wi, wj = profiles[i]['writes'], profiles[j]['writes']
        ri, rj = profiles[i]['reads'], profiles[j]['reads']
        return bool(wi & wj) or bool(wi & rj) or bool(ri & wj)

    def create_conflict_graph():
        graph = defaultdict(set)
        for i in range(n):
            for j in range(i+1, n):
                if has_conflict(i, j):
                    graph[i].add(j)
                    graph[j].add(i)
        return graph

    conflict_graph = create_conflict_graph()

    def greedy_topological():
        schedule = []
        remaining = set(range(n))
        while remaining:
            candidates = []
            for i in remaining:
                if not any(j in remaining for j in conflict_graph[i]):
                    candidates.append(i)

            if candidates:
                best = max(candidates, key=lambda x: -profiles[x]['length'])
                schedule.append(best)
                remaining.remove(best)
            else:
                best = min(remaining, key=lambda x: len(conflict_graph[x] & remaining))
                schedule.append(best)
                remaining.remove(best)
        return schedule

    def generate_diverse_schedules(num):
        schedules = []

        schedules.append(list(range(n)))

        schedules.append(greedy_topological())

        if n > 1:
            reverse_greedy = greedy_topological()[::-1]
            if reverse_greedy not in schedules:
                schedules.append(reverse_greedy)

        write_order = sorted(range(n), key=lambda i: -len(profiles[i]['writes']))
        if write_order not in schedules:
            schedules.append(write_order)

        read_order = sorted(range(n), key=lambda i: -len(profiles[i]['reads']))
        if read_order not in schedules:
            schedules.append(read_order)

        length_order = sorted(range(n), key=lambda i: -profiles[i]['length'])
        if length_order not in schedules:
            schedules.append(length_order)

        remaining = max(0, num - len(schedules))
        for _ in range(remaining):
            schedule = list(range(n))
            random.shuffle(schedule)
            if schedule not in schedules:
                schedules.append(schedule)

        return schedules[:num]

    def hill_climb(schedule, max_iterations=1000):
        current = schedule[:]
        current_cost = get_cost(current)
        best = current[:]
        best_cost = current_cost

        for _ in range(max_iterations):
            improved = False
            for i in range(n):
                for j in range(i+1, n):
                    neighbor = current[:]
                    neighbor[i], neighbor[j] = neighbor[j], neighbor[i]
                    neighbor_cost = get_cost(neighbor)

                    if neighbor_cost < current_cost:
                        current = neighbor
                        current_cost = neighbor_cost
                        improved = True
                        break
                if improved:
                    break

            if current_cost < best_cost:
                best = current[:]
                best_cost = current_cost

            if not improved:
                break

        return best, best_cost

    def simulated_annealing(initial_schedule, iterations):
        current = initial_schedule[:]
        current_cost = get_cost(current)
        best = current[:]
        best_cost = current_cost

        temp = 100.0
        cooling_rate = 0.99

        for iteration in range(iterations):
            i, j = random.sample(range(n), 2)
            neighbor = current[:]
            neighbor[i], neighbor[j] = neighbor[j], neighbor[i]
            neighbor_cost = get_cost(neighbor)

            delta = neighbor_cost - current_cost

            if delta < 0 or random.random() < math.exp(-delta / temp):
                current = neighbor
                current_cost = neighbor_cost

                if current_cost < best_cost:
                    best = current[:]
                    best_cost = current_cost

            temp *= cooling_rate

        return best, best_cost

    initial_schedules = generate_diverse_schedules(min(num_seqs, 50))

    best_cost = float('inf')
    best_schedule = None

    for schedule in initial_schedules:
        cost = get_cost(schedule)
        if cost < best_cost:
            best_cost = cost
            best_schedule = schedule[:]

    search_iterations = max(100, min(5000, num_seqs * 10))

    if best_schedule is not None:
        hc_schedule, hc_cost = hill_climb(best_schedule, max_iterations=search_iterations // 2)
        if hc_cost < best_cost:
            best_cost = hc_cost
            best_schedule = hc_schedule[:]

        sa_schedule, sa_cost = simulated_annealing(best_schedule, iterations=search_iterations)
        if sa_cost < best_cost:
            best_cost = sa_cost
            best_schedule = sa_schedule[:]

        final_hc, final_cost = hill_climb(best_schedule, max_iterations=500)
        if final_cost < best_cost:
            best_cost = final_cost
            best_schedule = final_hc[:]

    if best_schedule is None:
        best_schedule = list(range(n))
        best_cost = get_cost(best_schedule)

    return best_cost, best_schedule
